# ── Seeder (partial — articles continue below) ────────────────────────────────

async def seed() -> None:
    async with SessionLocal() as session:
        existing = await session.execute(
            select(Regulation).where(Regulation.name == "EU_AI_ACT")
        )
        if existing.scalar_one_or_none():
            print("✓ EU AI Act already seeded — skipping.")
            return

        await session.execute(text("CREATE EXTENSION IF NOT EXISTS vector"))

        regulation = Regulation(**EU_AI_ACT_REGULATION)
        session.add(regulation)
        await session.flush()

        version = RegulationVersion(regulation_id=regulation.id, **EU_AI_ACT_VERSION)
        session.add(version)
        await session.flush()

        for data in EU_AI_ACT_ARTICLES:
            session.add(Rule(
                regulation_id=regulation.id,
                regulation_version_id=version.id,
                **data,
            ))

        await session.commit()
        print(f"✅ EU AI Act seeded: 1 regulation, 1 version, {len(EU_AI_ACT_ARTICLES)} articles.")


if __name__ == "__main__":
    asyncio.run(seed())
